"""Webhook 転送のコア。"""


def build_forward_headers(headers: dict) -> dict:
    """hop-by-hop ヘッダを除いた転送用ヘッダを作る。"""
    hop_by_hop = {"connection", "keep-alive", "transfer-encoding", "upgrade"}
    return {k: v for k, v in headers.items() if k.lower() not in hop_by_hop}

